const approvedPosts = $('Fetch Approved Unscheduled').all();
const futureScheduled = $('Fetch Future Scheduled').all();

if (approvedPosts.length === 0) {
  return [];
}

// Luxon DateTime is available globally as DateTime
let start = DateTime.now().setZone('Europe/Berlin');

// Convert future scheduled times to a Set of strings to check for collisions
const scheduledSlots = new Set(futureScheduled.map(p => {
  if (!p.json.publish_at) return '';
  return DateTime.fromISO(p.json.publish_at).setZone('Europe/Berlin').toFormat('yyyy-MM-dd HH:mm');
}).filter(Boolean));

function getNextSlot(dt) {
  // Candidate 1: today at 09:00
  let c1 = dt.set({ hour: 9, minute: 0, second: 0, millisecond: 0 });
  if (c1 > dt) return c1;

  // Candidate 2: today at 15:00
  let c2 = dt.set({ hour: 15, minute: 0, second: 0, millisecond: 0 });
  if (c2 > dt) return c2;

  // Candidate 3: tomorrow at 09:00
  return dt.plus({ days: 1 }).set({ hour: 9, minute: 0, second: 0, millisecond: 0 });
}

const updates = [];
let currentPointer = start;

for (const post of approvedPosts) {
  let slot = getNextSlot(currentPointer);
  while (scheduledSlots.has(slot.toFormat('yyyy-MM-dd HH:mm'))) {
    slot = getNextSlot(slot);
  }

  updates.push({
    json: {
      id: post.json.id,
      publish_at: slot.toUTC().toISO(),
      timezone: 'Europe/Berlin'
    }
  });

  scheduledSlots.add(slot.toFormat('yyyy-MM-dd HH:mm'));
  currentPointer = slot;
}

return updates;
